            try KeychainService.shared.save(try JSONEncoder().encode(account), for: storageKey)
            DispatchQueue.main.async {
                self.account = account
                self.status = "Wallet created"
            }
        } catch {
            DispatchQueue.main.async {
                self.status = "Failed to save wallet"
            }
        }
    }

    func loadAccount() {
        do {
            let data = try KeychainService.shared.load(for: storageKey)
            let account = try JSONDecoder().decode(WalletAccount.self, from: data)
            DispatchQueue.main.async {
                self.account = account
                self.status = "Wallet loaded"
            }
        } catch {
            DispatchQueue.main.async {
                self.account = nil
                self.status = "No wallet found"
            }
        }
    }

    func deleteWallet() {
        KeychainService.shared.delete(for: storageKey)
        account = nil
        status = "Wallet deleted"
    }

    func sign(message: Data) -> String? {
        guard let account else { return nil }
        guard let privateData = Data(hexString: account.privateKeyHex),
              let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateData) else { return nil }
        let signature = try? privateKey.signature(for: message)
        return signature?.derRepresentation.hexString
