struct Transaction: Codable {
    let from: String
    let to: String
    let amount: Decimal
    let nonce: UInt64
    let chainId: String
    let timestamp: Date

    func signingPayload() -> Data {
        let payload = [
            from,
            to,
            NSDecimalNumber(decimal: amount).stringValue,
            String(nonce),
            chainId,
            String(Int(timestamp.timeIntervalSince1970))
        ].joined(separator: "|")
        return Data(payload.utf8)
    }
}

final class BlockchainService {
    static let shared = BlockchainService()
    private init() {}

    func fetchBalance(address: String) async throws -> Decimal {
        let url = URL(string: "https://example.com/api/balance?address=\(address)")!
        let (data, _) = try await URLSession.shared.data(from: url)
        let response = try JSONDecoder().decode(BalanceResponse.self, from: data)
        return response.balance
    }

    func submitTransaction(_ tx: SignedTransaction) async throws -> String {
        let url = URL(string: "https://example.com/api/submit")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONEncoder().encode(tx)
        let (data, _) = try await URLSession.shared.data(for: request)
        let response = try JSONDecoder().decode(SubmitResponse.self, from: data)
        return response.txHash
    }
}

struct BalanceResponse: Codable {
    let balance: Decimal
}

struct SubmitResponse: Codable {
    let txHash: String
}

struct SignedTransaction: Codable {
    let transaction: Transaction
    let signatureHex: String
    let publicKeyHex: String
}

extension Data {
    var hexString: String {
        map { String(format: "%02x", $0) }.joined()
    }

    init?(hexString: String) {
        let len = hexString.count
        guard len % 2 == 0 else { return nil }
        var data = Data(capacity: len / 2)
        var index = hexString.startIndex
        for _ in 0..<(len / 2) {
            let next = hexString.index(index, offsetBy: 2)
            guard let byte = UInt8(hexString[index..<next], radix: 16) else { return nil }
            data.append(byte)
            index = next
        }
        self = data
    }
}

struct ContentView: View {
    @StateObject private var wallet = WalletManager()
    @State private var toAddress = ""
    @State private var amount = ""
    @State private var nonce = "1"
    @State private var chainId = "1"
    @State private var balanceText = "—"
    @State private var txResult = ""
    @State private var isSubmitting = false

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Wallet")) {
                    Text(wallet.status)
                    if let account = wallet.account {
                        Text("Address: \(account.address)")
                            .font(.footnote)
                            .textSelection(.enabled)
                        Button("Copy Address") {
                            UIPasteboard.general.string = account.address
                        }
                        Button("Delete Wallet", role: .destructive) {
                            wallet.deleteWallet()
                        }
                    } else {
                        Button("Create Wallet") {
                            wallet.createWallet()
                        }
                    }
                }

                Section(header: Text("Balance")) {
                    Text(balanceText)
                    Button("Refresh Balance") {
                        Task {
                            guard let address = wallet.account?.address else { return }
                            do {
                                let balance = try await BlockchainService.shared.fetchBalance(address: address)
                                balanceText = "\(balance)"
                            } catch {
                                balanceText = "Error"
                            }
                        }
                    }
                }

                Section(header: Text("Send Transaction")) {
                    TextField("To Address", text: $toAddress)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                    TextField("Amount", text: $amount)
                        .keyboardType(.decimalPad)
                    TextField("Nonce", text: $nonce)
                        .keyboardType(.numberPad)
                    TextField("Chain ID", text: $chainId)
                    Button(isSubmitting ? "Sending..." : "Sign & Send") {
                        Task {
                            await signAndSend()
                        }
                    }
                    .disabled(wallet.account == nil || isSubmitting)
                    Text(txResult)
                        .font(.footnote)
                        .textSelection(.enabled)
                }
            }
            .navigationTitle("Crypto Wallet MVP")
        }
    }

    private func signAndSend() async {
        guard let account = wallet.account,
              let amountDecimal = Decimal(string: amount),
              let nonceValue = UInt64(nonce) else {
            txResult = "Invalid input"
            return
        }

        isSubmitting = true
        defer { isSubmitting = false }

        let tx = Transaction(
            from: account.address,
            to: toAddress,
            amount: amountDecimal,
            nonce: nonceValue,
            chainId: chainId,
            timestamp: Date()
        )

        guard let signatureHex = wallet.sign(message: tx.signingPayload()) else {
            txResult = "Signing failed"
            return
        }

        let signed = SignedTransaction(
            transaction: tx,
            signatureHex: signatureHex,
            publicKeyHex: account.publicKeyHex
        )

        do {
            let txHash = try await BlockchainService.shared.submitTransaction(signed)
            txResult = "Submitted: \(txHash)"
        } catch {
            txResult = "Submit failed"
        }
    }
}